    const docSnap = await getDoc(docRef);
    return docSnap.exists() ? ({ ...docSnap.data(), id: docSnap.id } as Document) : null;
  },
  getRelatedDocIds: async (project: string, micro: string, type: string): Promise<string[]> => {
      const q = query(
          collection(db, "documents"), 
          where("project", "==", project),
          where("docType", "==", type)
      );
      const snap = await getDocs(q);
      const normalizedMicro = normalizeHeader(micro);
      return snap.docs
          .filter(d => normalizeHeader(d.data().microprocess || d.data().title.split(' - ')[0]) === normalizedMicro)
          .map(d => d.id);
  },
  updateDeadline: async (docId: string, expectedEndDate: string) => {
    const docRef = doc(db, "documents", docId);
    await updateDoc(docRef, { expectedEndDate });
  },
  ignoreInconsistency: async (docId: string, version: string, state: string) => {
      const docRef = doc(db, "documents", docId);
      await updateDoc(docRef, { ignoredInconsistency: `${version}|${state}` });
  },
  create: async (title: string, description: string, author: User, initialState?: DocState, initialVersion?: string, initialProgress?: number, file?: File, hierarchy?: any, existingId?: string): Promise<Document> => {
    const state = initialState || DocState.INITIATED;
    const isSubmission = [DocState.INTERNAL_REVIEW, DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(state);
    const version = initialVersion || '0.0';
    const info = determineStateFromVersion(version);
    const progress = initialProgress !== undefined ? initialProgress : info.progress;

    let finalDocId: string;
    let finalDocData: Document;

    if (existingId) {
        finalDocId = existingId;
        const docRef = doc(db, "documents", existingId);
        const oldSnap = await getDoc(docRef);
        const oldData = oldSnap.data() as Document;
        const updateData: Partial<Document> = { state, version, progress, description, hasPendingRequest: isSubmission, updatedAt: new Date().toISOString(), ignoredInconsistency: null as any };
        await updateDoc(docRef, updateData);
        await HistoryService.log(existingId, author, 'Nueva Versión (Carga)', oldData.state, state, `Carga de archivo versión ${version}`, version);
        finalDocData = { ...oldData, ...updateData, id: existingId } as Document;
    } else {
        const mergedAssignees = Array.from(new Set([...(hierarchy?.assignees || []), author.id]));
        const newDocData: Omit<Document, 'id'> = {
          title, description, authorId: author.id, authorName: author.name, assignedTo: author.id, assignees: mergedAssignees, state, version, progress, hasPendingRequest: isSubmission, files: [], createdAt: new Date().toISOString(), updatedAt: new Date().toISOString(), project: hierarchy?.project, macroprocess: hierarchy?.macro, process: hierarchy?.process, microprocess: hierarchy?.micro, docType: hierarchy?.docType
        };
        const docRef = await addDoc(collection(db, "documents"), newDocData);
        finalDocId = docRef.id;
        await HistoryService.log(docRef.id, author, 'Creación', DocState.NOT_STARTED, state, `Iniciado Versión ${version}`, version);
        finalDocData = { ...newDocData, id: docRef.id } as Document;
    }

    // --- NOTIFICACIÓN ROBUSTA DE CARGA ---
    const allUsers = await UserService.getAll();
    const recipientIds = new Set<string>();

    allUsers.forEach(u => {
        const role = String(u.role || '').toUpperCase();
        if (role === 'ADMIN' || role === 'COORDINATOR' || role === 'COORDINADOR') {
            recipientIds.add(u.id);
        }
    });

    if (finalDocData.assignees) {
        finalDocData.assignees.forEach(uid => recipientIds.add(uid));
    }

    recipientIds.delete(author.id);

    const displayVersion = formatVersionForDisplay(version);
    const titleNotif = `Actualización: ${finalDocData.microprocess}`;
    const msgNotif = `${author.name} ha cargado la versión ${displayVersion} del informe ${finalDocData.docType}.`;

    const promises = Array.from(recipientIds).map(uid => 
        NotificationService.create(uid, finalDocId, 'UPLOAD', titleNotif, msgNotif, author.name)
    );
    await Promise.all(promises);

    return finalDocData;
  },
  delete: async (id: string) => { await deleteDoc(doc(db, "documents", id)); },

  revertLastTransition: async (docId: string): Promise<boolean> => {
      const histQ = query(collection(db, "history"), where("documentId", "==", docId));
      const histSnap = await getDocs(histQ);
      if (histSnap.empty) return true;
      const sortedHistory = histSnap.docs.map(d => ({ ...d.data(), _id: d.id, _ref: d.ref } as any)).sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
      if (sortedHistory.length <= 1) {
          await deleteDoc(doc(db, "documents", docId));
          const batch = writeBatch(db);
          histSnap.docs.forEach(d => batch.delete(d.ref));
          await batch.commit();
          return true;
      }
      const lastAction = sortedHistory[0]; 
      const previousAction = sortedHistory[1]; 
      const docRef = doc(db, "documents", docId);
      const restoredVersion = previousAction.version || '0.0';
      const info = determineStateFromVersion(restoredVersion);
      await updateDoc(docRef, { state: previousAction.newState, version: restoredVersion, progress: info.progress, updatedAt: previousAction.timestamp, hasPendingRequest: [DocState.INTERNAL_REVIEW, DocState.SENT_TO_REFERENT, DocState.SENT_TO_CONTROL].includes(previousAction.newState), ignoredInconsistency: null as any });
      await deleteDoc(lastAction._ref);
      return false;
  },

  syncMetadata: async (docId: string, user: User, forcedState?: DocState): Promise<void> => {
      const docRef = doc(db, "documents", docId);
      const docSnap = await getDoc(docRef);
      if(!docSnap.exists()) return;
      const data = docSnap.data() as Document;

      let state: DocState;
      let progress: number;

      if (forcedState) {
          state = forcedState;
          progress = STATE_CONFIG[forcedState].progress;
      } else {
          const autoInfo = determineStateFromVersion(data.version);
          state = autoInfo.state;
          progress = autoInfo.progress;
      }

      const shouldHavePending = [
          DocState.INTERNAL_REVIEW, 
          DocState.SENT_TO_REFERENT, 
          DocState.REFERENT_REVIEW, 
          DocState.SENT_TO_CONTROL, 
          DocState.CONTROL_REVIEW
      ].includes(state);

      const needsUpdate = data.state !== state || 
                          data.progress !== progress || 
                          data.hasPendingRequest !== shouldHavePending;

      if (needsUpdate) {
          await updateDoc(docRef, { 
              state, 
              progress, 
              hasPendingRequest: shouldHavePending,
              updatedAt: new Date().toISOString(),
              ignoredInconsistency: null as any
          });
          await HistoryService.log(docId, user, 'Sincronización Sistema', data.state, state, `Corrección ${forcedState ? 'manual' : 'automática'}: ${state} / ${progress}% / Alerta: ${shouldHavePending}`, data.version);
      }
  },

  transitionState: async (docId: string, user: User, action: any, comment: string, file?: File, customVersion?: string): Promise<void> => {
      const docRef = doc(db, "documents", docId);
      const docSnap = await getDoc(docRef);
      if(!docSnap.exists()) throw new Error("Documento no encontrado");
      const currentDoc = docSnap.data() as Document;

      let newState = currentDoc.state;
      let newVersion = currentDoc.version;
      let hasPending = currentDoc.hasPendingRequest;

      const actionLabels: Record<string, string> = { 
          'APPROVE': 'Aprobación', 'REJECT': 'Rechazo', 'COMMENT': 'Observación', 
          'ADVANCE': 'Avance de Flujo' 
      };
      const displayAction = actionLabels[action] || action;

      if (customVersion) {
        newVersion = customVersion;
        const info = determineStateFromVersion(customVersion);
        newState = info.state;
      }

      if (action === 'APPROVE') hasPending = false;
      else if (action === 'REJECT') { hasPending = false; newState = determineStateFromVersion(newVersion).state; }

      const { progress: newProgress } = determineStateFromVersion(newVersion);
      await updateDoc(docRef, { 
          state: newState, 
          version: newVersion, 
          progress: newProgress, 
          hasPendingRequest: hasPending, 
          updatedAt: new Date().toISOString(),
          ignoredInconsistency: null as any 
      });
      await HistoryService.log(docId, user, displayAction, currentDoc.state, newState, comment, newVersion);

      const allUsers = await UserService.getAll();
      const finalRecipientIds = new Set<string>();

      allUsers.forEach(u => {
          const role = String(u.role || '').toUpperCase();
          if (role === 'ADMIN' || role === 'COORDINATOR' || role === 'COORDINADOR') {
              finalRecipientIds.add(u.id);
          }
      });

      if (currentDoc.authorId) {
          finalRecipientIds.add(currentDoc.authorId);
      }

      if (currentDoc.assignees) {
          currentDoc.assignees.forEach(uid => finalRecipientIds.add(uid));
      }

      finalRecipientIds.delete(user.id);

      const typeMapping: Record<string, Notification['type']> = {
          'APPROVE': 'APPROVAL', 'REJECT': 'REJECTION', 
          'COMMENT': 'COMMENT'
      };
      const type = typeMapping[action] || 'COMMENT';
      const displayVersion = formatVersionForDisplay(newVersion);
      const title = `${displayAction}: ${currentDoc.microprocess}`;
      const msg = `${user.name} ha realizado una ${displayAction.toLowerCase()} en "${currentDoc.title}" (${displayVersion}).`;

      const notificationPromises = Array.from(finalRecipientIds)
          .filter(uid => uid && uid.trim() !== '')
          .map(uid => NotificationService.create(uid, docId, type, title, msg, user.name));

      await Promise.all(notificationPromises);
  }
};

export const HierarchyService = {
  getFullHierarchy: async (): Promise<FullHierarchy> => {
    const q = query(collection(db, "process_matrix"));
    const snapshot = await getDocs(q);
    const hierarchy: FullHierarchy = {};
    snapshot.docs.forEach(doc => {
      const data = doc.data();
      const node: ProcessNode = { name: data.name, docId: doc.id, assignees: data.assignees || [], referentIds: data.referentIds || [], requiredTypes: data.requiredTypes || [], active: data.active !== false };
      if (!hierarchy[data.project]) hierarchy[data.project] = {};
      if (!hierarchy[data.project][data.macroprocess || 'Sin Macro']) hierarchy[data.project][data.macroprocess || 'Sin Macro'] = {};
      if (!hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process]) hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process] = [];
      hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process].push(node);
    });
    return hierarchy;
  },
  getUserHierarchy: async (userId: string): Promise<UserHierarchy> => {
      const q = query(collection(db, "process_matrix"), where("assignees", "array-contains", userId));
      const snapshot = await getDocs(q);
      const hierarchy: UserHierarchy = {};
      snapshot.docs.forEach(doc => {
          const data = doc.data();
          if (!hierarchy[data.project]) hierarchy[data.project] = {};
          if (!hierarchy[data.project][data.macroprocess || 'Sin Macro']) hierarchy[data.project][data.macroprocess || 'Sin Macro'] = {};
          if (!hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process]) hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process] = [];
          hierarchy[data.project][data.macroprocess || 'Sin Macro'][data.process].push(data.name);
      });
      return hierarchy;
  },
  updateMatrixAssignment: async (docId: string, assignees: string[]) => { await updateDoc(doc(db, "process_matrix", docId), { assignees }); },
  updateReferentLinks: async (referentId: string, selectedDocIds: string[]) => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => {
          let referents = d.data().referentIds || [];
          const isSelected = selectedDocIds.includes(d.id);
          if (isSelected && !referents.includes(referentId)) batch.update(d.ref, { referentIds: [...referents, referentId] });
          else if (!isSelected && referents.includes(referentId)) batch.update(d.ref, { referentIds: referents.filter((id:string) => id !== referentId) });
      });
      await batch.commit();
  },
  toggleRequiredType: async (docId: string, type: DocType) => {
      const ref = doc(db, "process_matrix", docId);
      const snap = await getDoc(ref);
      if (snap.exists()) {
          const current = new Set(snap.data().requiredTypes || []);
          if (current.has(type)) current.delete(type); else current.add(type);
          await updateDoc(ref, { requiredTypes: Array.from(current) });
      }
  },
  addMicroprocess: async (project: string, macro: string, process: string, name: string, assignees: string[], requiredTypes: string[]) => {
      const id = generateMatrixId(project, name);
      await setDoc(doc(db, "process_matrix", id), { project, macroprocess: macro, process, name, assignees, referentIds: [], requiredTypes, active: true });
  },
  deleteMicroprocess: async (docId: string) => { await deleteDoc(doc(db, "process_matrix", docId)); },
  getRequiredTypesMap: async (): Promise<Record<string, DocType[]>> => {
      const q = query(collection(db, "process_matrix"));
      const snapshot = await getDocs(q);
      const map: Record<string, DocType[]> = {};
      snapshot.docs.forEach(d => {
          const key = `${normalizeHeader(d.data().project)}|${normalizeHeader(d.data().name)}`;
          map[key] = d.data().requiredTypes || [];
      });
      return map;
  },
  toggleProcessStatus: async (docId: string, currentStatus: boolean) => { await updateDoc(doc(db, "process_matrix", docId), { active: !currentStatus }); },
  deleteHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS', name: string, context: { project?: string, macro?: string }) => {
      let q;
      if (level === 'PROJECT') q = query(collection(db, "process_matrix"), where("project", "==", name));
      else if (level === 'MACRO') q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", name));
      else q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", name));
      const snapshot = await getDocs(q);
      const batch = writeBatch(db);
      snapshot.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
  },
  updateHierarchyNode: async (level: 'PROJECT' | 'MACRO' | 'PROCESS' | 'MICRO', oldName: string, newName: string, context: { project?: string, macro?: string, process?: string, docId?: string }) => {
      const batch = writeBatch(db);

      if (level === 'MICRO' && context.docId) {
          const matrixRef = doc(db, "process_matrix", context.docId);
          batch.update(matrixRef, { name: newName });

          const docsQ = query(collection(db, "documents"), where("project", "==", context.project), where("microprocess", "==", oldName));
          const docsSnap = await getDocs(docsQ);
          docsSnap.forEach(d => {
              batch.update(d.ref, { microprocess: newName, title: d.data().title.replace(oldName, newName) });
          });
      } else {
          let q;
          if (level === 'PROJECT') q = query(collection(db, "process_matrix"), where("project", "==", oldName));
          else if (level === 'MACRO') q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", oldName));
          else q = query(collection(db, "process_matrix"), where("project", "==", context.project), where("macroprocess", "==", context.macro), where("process", "==", oldName));

          const snapshot = await getDocs(q);
          snapshot.docs.forEach(d => {
              const update: any = {};
              if (level === 'PROJECT') update.project = newName;
              else if (level === 'MACRO') update.macroprocess = newName;
              else if (level === 'PROCESS') update.process = newName;
              batch.update(d.ref, update);
          });
      }

      await batch.commit();
  },
  moveMicroprocess: async (docId: string, targetProject: string, targetMacro: string, targetProcess: string) => {
      await updateDoc(doc(db, "process_matrix", docId), { project: targetProject, macroprocess: targetMacro, process: targetProcess });
  },
  seedDefaults: async () => {
      const batch = writeBatch(db);
      for (const row of REQUIRED_DOCS_MATRIX) {
           const [project, micro, asis, fce, pm, tobe] = row;
           const requiredTypes: string[] = [];
           if (asis) requiredTypes.push('AS IS'); if (fce) requiredTypes.push('FCE'); if (pm) requiredTypes.push('PM'); if (tobe) requiredTypes.push('TO BE');
           batch.set(doc(db, "process_matrix", generateMatrixId(project, micro)), { project, macroprocess: 'Macroproceso General', process: 'Proceso General', name: micro, assignees: [], referentIds: [], requiredTypes, active: true });
      }
      await batch.commit();
  }
};

export const DatabaseService = {
  exportData: async (): Promise<string> => {
    const collections = ["users", "documents", "history", "process_matrix", "notifications", "referents"];
    const exportObj: any = {};
    for (const colName of collections) {
      const snap = await getDocs(collection(db, colName));
      exportObj[colName] = snap.docs.map(d => ({ ...d.data(), _id: d.id }));
    }
    return JSON.stringify(exportObj, null, 2);
  },

  importData: async (jsonContent: string): Promise<void> => {
    const data = JSON.parse(jsonContent);
    const collections = ["users", "documents", "history", "process_matrix", "notifications", "referents"];
    for (const colName of collections) {
      await deleteCollectionInBatches(colName);
      if (data[colName]) {
        for (const item of data[colName]) {
          const { _id, ...rest } = item;
          if (_id) {
             await setDoc(doc(db, colName, _id), rest);
          } else {
             await addDoc(collection(db, colName), rest);
          }
        }
      }
    }
  },

  fullSystemResetAndImport: async (
    rulesCsv: string, 
    historyCsv: string, 
    onProgress: (percent: number, status: string) => void
  ): Promise<{ created: number, historyMatched: number }> => {
    onProgress(5, "Iniciando limpieza de base de datos...");
    await deleteCollectionInBatches("documents");
    await deleteCollectionInBatches("history");
    await deleteCollectionInBatches("process_matrix");
    await deleteCollectionInBatches("notifications");

    onProgress(20, "Procesando matriz de procesos...");
    const rulesRows = rulesCsv.split(/\r?\n/).filter(line => line.trim().length > 0);
    const dataRows = rulesRows.slice(1);

    let createdCount = 0;
    let historyMatchedCount = 0;

    for (const row of dataRows) {
        const parts = row.split(';').map(p => p.trim());
        if (parts.length < 5) continue;

        const [macro, proc, micro, analystsStr, project, asis, fce, pm, tobe] = parts;
        const requiredTypes: DocType[] = [];
        if (asis === '1') requiredTypes.push('AS IS');
        if (fce === '1') requiredTypes.push('FCE');
        if (pm === '1') requiredTypes.push('PM');
        if (tobe === '1') requiredTypes.push('TO BE');

        const analysts = analystsStr ? analystsStr.split(',').map(a => a.trim()).filter(a => a.length > 0) : [];
        const matrixId = generateMatrixId(project, micro);

        const nodeData = {
            project,
            macroprocess: macro,
            process: proc,
            name: micro,
            assignees: analysts,
            referentIds: [],
            requiredTypes,
            active: true
        };

        await setDoc(doc(db, "process_matrix", matrixId), nodeData);
        createdCount++;
    }

    onProgress(60, "Vinculando historial de documentos...");
    if (historyCsv && historyCsv.trim().length > 0) {
        const historyRows = historyCsv.split(/\r?\n/).filter(line => line.trim().length > 0).slice(1);
        const systemUser: User = { 
            id: 'system', 
            name: 'Sistema (Carga Inicial)', 
            role: UserRole.ADMIN, 
            email: 'admin@empresa.com', 
            avatar: '', 
            organization: 'Soporte',
            active: true
        };

        for (const row of historyRows) {
            const parts = row.split(';').map(p => p.trim());
            if (parts.length < 5) continue;

            const [project, macro, proc, micro] = parts;
            const types: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];

            for (let i = 0; i < types.length; i++) {
                const vIdx = 4 + (i * 2);
                const fIdx = 5 + (i * 2);
                const version = parts[vIdx];
                const dateStr = parts[fIdx];

                if (version && version !== '-' && version !== '0') {
                    const { state, progress } = determineStateFromVersion(version);
                    const timestamp = parseSpanishDate(dateStr);

                    const newDoc: Omit<Document, 'id'> = {
                        title: `${micro} - ${types[i]}`,
                        description: 'Carga histórica inicial',
                        authorId: 'system',
                        authorName: 'Sistema',
                        assignedTo: 'system',
                        assignees: [], 
                        state,
                        version,
                        progress,
                        hasPendingRequest: false,
                        files: [],
                        createdAt: timestamp,
                        updatedAt: timestamp,
                        project,
                        macroprocess: macro,
                        process: proc,
                        microprocess: micro,
                        docType: types[i]
                    };

                    const docRef = await addDoc(collection(db, "documents"), newDoc);
                    await HistoryService.log(
                      docRef.id, 
                      systemUser, 
                      'Migración Histórica', 
                      DocState.NOT_STARTED, 
                      state, 
                      'Carga inicial desde archivo histórico', 
                      version, 
                      timestamp
                    );
                    historyMatchedCount++;
                }
            }
        }
    }

    onProgress(100, "Finalizado.");
    return { created: createdCount, historyMatched: historyMatchedCount };
  }
};

import React, { useState, useEffect, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { DocumentService, determineStateFromVersion, formatVersionForDisplay } from '../services/firebaseBackend';
import { Document, User, DocState } from '../types';
import { STATE_CONFIG } from '../constants';
import { History, AlertTriangle, RefreshCw, CheckCircle2, Search, Loader2, Info, ArrowRight, X, ExternalLink, FileText, Slash, ChevronDown } from 'lucide-react';

interface Props {
    user: User;
}

const AdminEventLog: React.FC<Props> = ({ user }) => {
    const [documents, setDocuments] = useState<Document[]>([]);
    const [loading, setLoading] = useState(true);
    const [syncingAll, setSyncingAll] = useState(false);
    const [syncingId, setSyncingId] = useState<string | null>(null);
    const [discardingId, setDiscardingId] = useState<string | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    // Estado para manejar la selección manual de estados en la tabla
    const [manualStates, setManualStates] = useState<Record<string, DocState>>({});

    useEffect(() => {
        loadDocuments();
    }, []);

    const loadDocuments = async () => {
        setLoading(true);
        try {
            const data = await DocumentService.getAll();
            setDocuments(data);

            // Inicializar estados manuales con el estado actual registrado
            const initialManual: Record<string, DocState> = {};
            data.forEach(d => {
                initialManual[d.id] = d.state;
            });
            setManualStates(initialManual);
        } catch (error) {
            console.error("Error loading docs for event log:", error);
        } finally {
            setLoading(false);
        }
    };

    const inconsistentDocs = useMemo(() => {
        return documents.filter(doc => {
            const expectedInfo = determineStateFromVersion(doc.version);
            const expectedState = expectedInfo.state;
            const expectedPending = [
                DocState.INTERNAL_REVIEW, 
                DocState.SENT_TO_REFERENT, 
                DocState.REFERENT_REVIEW, 
                DocState.SENT_TO_CONTROL, 
                DocState.CONTROL_REVIEW
            ].includes(expectedState);

            const isInconsistent = doc.state !== expectedState || doc.hasPendingRequest !== expectedPending;

            // Si el administrador ya descartó esta combinación específica, no la mostramos como inconsistente
            const currentHash = `${doc.version}|${doc.state}`;
            if (isInconsistent && doc.ignoredInconsistency === currentHash) {
                return false;
            }

            return isInconsistent;
        });
    }, [documents]);

    const filteredInconsistent = useMemo(() => {
        if (!searchTerm) return inconsistentDocs;
        const term = searchTerm.toLowerCase();
        return inconsistentDocs.filter(d => 
            d.title.toLowerCase().includes(term) || 
            d.microprocess?.toLowerCase().includes(term) ||
            d.project?.toLowerCase().includes(term)
        );
    }, [inconsistentDocs, searchTerm]);

    const handleSync = async (docId: string) => {
        setSyncingId(docId);
        try {
            // Usamos el estado seleccionado manualmente en el listbox
            const forcedState = manualStates[docId];
            await DocumentService.syncMetadata(docId, user, forcedState);
            // Actualizar localmente para reflejar el cambio inmediato
            await loadDocuments();
        } catch (e: any) {
            alert("Error al sincronizar: " + e.message);
        } finally {
            setSyncingId(null);
        }
    };

    const handleDiscard = async (docId: string, version: string, state: string) => {
        if (!window.confirm("¿Está seguro de descartar esta inconsistencia? El sistema omitirá esta alerta hasta que el documento cambie de versión o estado.")) return;
        setDiscardingId(docId);
        try {
            await DocumentService.ignoreInconsistency(docId, version, state);
            await loadDocuments();
        } catch (e: any) {
            alert("Error al descartar: " + e.message);
        } finally {
            setDiscardingId(null);
        }
    };

    const handleSyncAll = async () => {
        if (filteredInconsistent.length === 0) return;
        if (!window.confirm(`¿Está seguro de sincronizar automáticamente los ${filteredInconsistent.length} documentos? El sistema aplicará la lógica de nomenclatura institucional a todos ellos.`)) return;

        setSyncingAll(true);
        try {
            const promises = filteredInconsistent.map(d => DocumentService.syncMetadata(d.id, user));
            await Promise.all(promises);
            await loadDocuments();
            alert("Sincronización masiva completada con éxito.");
        } catch (e: any) {
            alert("Error en sincronización masiva: " + e.message);
        } finally {
            setSyncingAll(false);
        }
    };

    const handleManualStateChange = (docId: string, newState: DocState) => {
        setManualStates(prev => ({ ...prev, [docId]: newState }));
    };

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Analizando integridad de la base de datos...</div>;

    return (
        <div className="space-y-6 pb-12 animate-fadeIn max-w-6xl mx-auto">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <History className="text-indigo-600" />
                        Log de Eventos e Integridad
                    </h1>
                    <p className="text-slate-500">Buffer de inconsistencias detectadas automáticamente en metadatos.</p>
                </div>
                {inconsistentDocs.length > 0 && (
                    <button 
                        onClick={handleSyncAll}
                        disabled={syncingAll}
                        className="flex items-center gap-2 px-6 py-2.5 bg-amber-600 text-white rounded-xl font-black text-xs uppercase tracking-widest shadow-lg shadow-amber-100 hover:bg-amber-700 transition-all active:scale-95 disabled:opacity-50"
                    >
                        {syncingAll ? <Loader2 size={16} className="animate-spin" /> : <RefreshCw size={16} />}
                        Sincronización Masiva ({inconsistentDocs.length})
                    </button>
                )}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Documentos Analizados</p>
                    <p className="text-3xl font-black text-slate-900">{documents.length}</p>
                </div>
                <div className={`bg-white p-6 rounded-2xl border shadow-sm transition-colors ${inconsistentDocs.length > 0 ? 'border-amber-200' : 'border-slate-200'}`}>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Inconsistencias Totales</p>
                    <p className={`text-3xl font-black ${inconsistentDocs.length > 0 ? 'text-amber-600' : 'text-slate-900'}`}>{inconsistentDocs.length}</p>
                </div>
                <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Integridad del Sistema</p>
                    <p className="text-3xl font-black text-slate-900">
                        {documents.length > 0 ? Math.round(((documents.length - inconsistentDocs.length) / documents.length) * 100) : 100}%
                    </p>
                </div>
            </div>

            <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden min-h-[400px]">
                <div className="p-4 bg-slate-50 border-b border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
                    <div className="flex items-center gap-2 text-slate-700 font-bold text-sm">
                        <AlertTriangle size={18} className={inconsistentDocs.length > 0 ? 'text-amber-500' : 'text-green-500'} />
                        Listado de Inconsistencias
                    </div>
                    <div className="relative w-full md:w-64">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="text" 
                            placeholder="Buscar por microproceso..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-9 p-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                        />
                    </div>
                </div>

                <div className="overflow-x-auto">
                    <table className="w-full text-sm text-left">
                        <thead className="text-[10px] text-slate-400 uppercase font-bold bg-slate-50/50 border-b border-slate-100">
                            <tr>
                                <th className="px-6 py-4">Documento / Proyecto</th>
                                <th className="px-6 py-4">Estado Registrado (Editar)</th>
                                <th className="px-6 py-4">Versión Cargada</th>
                                <th className="px-6 py-4">Sugerencia Nomenclatura</th>
                                <th className="px-6 py-4 text-right">Acciones de Auditoría</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                            {filteredInconsistent.length === 0 ? (
                                <tr>
                                    <td colSpan={5} className="py-20 text-center">
                                        <div className="flex flex-col items-center justify-center text-slate-400">
                                            <CheckCircle2 size={48} className="text-green-200 mb-3" />
                                            <p className="font-bold text-slate-500">¡Sistema Íntegro!</p>
                                            <p className="text-xs">No se han detectado inconsistencias en los metadatos.</p>
                                        </div>
                                    </td>
                                </tr>
                            ) : filteredInconsistent.map(doc => {
                                const info = determineStateFromVersion(doc.version);
                                const isPendingMismatch = doc.hasPendingRequest !== [DocState.INTERNAL_REVIEW, DocState.SENT_TO_REFERENT, DocState.REFERENT_REVIEW, DocState.SENT_TO_CONTROL, DocState.CONTROL_REVIEW].includes(info.state);
                                const currentManualState = manualStates[doc.id] || doc.state;

                                return (
                                    <tr key={doc.id} className="hover:bg-amber-50/30 transition-colors group">
                                        <td className="px-6 py-4">
                                            <Link to={`/doc/${doc.id}`} className="block group/title">
                                                <div className="font-black text-slate-800 leading-tight mb-0.5 group-hover/title:text-indigo-600 transition-colors flex items-center gap-1.5">
                                                    <FileText size={14} className="text-slate-300 group-hover/title:text-indigo-400" />
                                                    {doc.title}
                                                </div>
                                            </Link>
                                            <div className="flex items-center gap-2 mt-1">
                                                <div className="flex items-center gap-1.5">
                                                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{doc.project}</span>
                                                    <span className="text-[9px] text-slate-300">•</span>
                                                    <span className="text-[9px] font-bold text-indigo-500 uppercase">{doc.docType}</span>
                                                </div>
                                                <Link 
                                                    to={`/doc/${doc.id}`} 
                                                    className="text-[9px] font-black text-indigo-600 uppercase tracking-tighter bg-indigo-50 px-1.5 py-0.5 rounded border border-indigo-100 opacity-0 group-hover:opacity-100 transition-opacity flex items-center gap-1"
                                                >
                                                    Ver Detalle <ExternalLink size={8} />
                                                </Link>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="relative group/select">
                                                <select 
                                                    value={currentManualState}
                                                    onChange={(e) => handleManualStateChange(doc.id, e.target.value as DocState)}
                                                    className={`appearance-none w-full pl-3 pr-8 py-1.5 rounded-lg text-[10px] font-bold border transition-all cursor-pointer outline-none focus:ring-2 focus:ring-indigo-500/20
                                                        ${STATE_CONFIG[currentManualState].color}`}
                                                >
                                                    {Object.entries(STATE_CONFIG).map(([key, cfg]) => (
                                                        <option key={key} value={key} className="bg-white text-slate-700">{cfg.label.split('(')[0].trim()}</option>
                                                    ))}
                                                </select>
                                                <ChevronDown size={14} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-500 pointer-events-none" />
                                            </div>
                                            {doc.hasPendingRequest && (
                                                <div className="mt-1 text-[8px] font-black text-blue-600 uppercase tracking-tighter flex items-center gap-1 ml-1">
                                                    <div className="w-1 h-1 rounded-full bg-blue-500 animate-pulse"></div>
                                                    Alerta de Gestión Registrada
                                                </div>
                                            )}
                                        </td>
                                        <td className="px-6 py-4">
                                            <span className="font-mono bg-slate-100 px-1.5 py-0.5 rounded text-[11px] font-black text-slate-600">
                                                {formatVersionForDisplay(doc.version)}
                                            </span>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col gap-1">
                                                {doc.state !== info.state && (
                                                    <div className="flex items-center gap-1.5 text-rose-600 text-[11px] font-bold bg-rose-50/50 px-2 py-1 rounded border border-rose-100">
                                                        <Info className="w-3 h-3" />
                                                        Esperado: {STATE_CONFIG[info.state].label.split('(')[0]}
                                                    </div>
                                                )}
                                                {isPendingMismatch && (
                                                    <div className="flex items-center gap-1.5 text-amber-600 text-[11px] font-bold bg-amber-50/50 px-2 py-1 rounded border border-amber-100">
                                                        <AlertTriangle className="w-3 h-3" />
                                                        Alerta desincronizada
                                                    </div>
                                                )}
                                                {doc.state === info.state && !isPendingMismatch && (
                                                    <div className="flex items-center gap-1.5 text-green-600 text-[11px] font-bold">
                                                        <CheckCircle2 className="w-3 h-3" />
                                                        Coherente por nomenclatura
                                                    </div>
                                                )}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <div className="flex justify-end gap-2">
                                                <button 
                                                    onClick={() => handleDiscard(doc.id, doc.version, doc.state)}
                                                    disabled={discardingId === doc.id}
                                                    className="flex items-center gap-1.5 px-3 py-1.5 bg-slate-100 text-slate-600 hover:bg-slate-200 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all active:scale-95 disabled:opacity-50"
                                                >
                                                    {discardingId === doc.id ? <Loader2 className="w-3 h-3 animate-spin" /> : <Slash className="w-3 h-3" />}
                                                    Descartar
                                                </button>
                                                <button 
                                                    onClick={() => handleSync(doc.id)}
                                                    disabled={syncingId === doc.id}
                                                    className="flex items-center gap-1.5 px-4 py-1.5 bg-indigo-600 text-white hover:bg-indigo-700 rounded-lg text-[10px] font-black uppercase tracking-widest shadow-md transition-all active:scale-95 disabled:opacity-50"
                                                >
                                                    {syncingId === doc.id ? <RefreshCw className="w-3 h-3 animate-spin" /> : <RefreshCw className="w-3 h-3" />}
                                                    Sincronizar
                                                </button>
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>

                {filteredInconsistent.length > 0 && (
                    <div className="p-4 bg-slate-50 border-t border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
                        <p className="text-[10px] text-slate-500 font-medium italic">
                            * Seleccione manualmente el estado en el listbox y presione "Sincronizar" para forzar la coherencia. El sistema ajustará automáticamente el progreso y las alertas asociadas.
                        </p>
                        <div className="flex items-center gap-4">
                             <div className="flex items-center gap-1.5">
                                <div className="w-2 h-2 rounded-full bg-rose-500"></div>
                                <span className="text-[9px] font-bold text-slate-400 uppercase">Estado Crítico</span>
                             </div>
                             <div className="flex items-center gap-1.5">
                                <div className="w-2 h-2 rounded-full bg-amber-500"></div>
                                <span className="text-[9px] font-bold text-slate-400 uppercase">Alerta Gestión</span>
                             </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export default AdminEventLog;

import React, { useEffect, useState, useMemo } from 'react';
import { DocumentService, UserService, HierarchyService, normalizeHeader, formatVersionForDisplay } from '../services/firebaseBackend';
import { Document, User, DocState, UserRole, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    CalendarRange, Search, Loader2, Clock, 
    Calendar, Layers, TrendingUp, Save, X, ArrowRight, 
    FileSpreadsheet, CheckCircle, ZoomIn, ZoomOut, Activity, Target,
    ChevronRight, ChevronDown, Maximize2, Minimize2, Filter
} from 'lucide-react';

interface Props {
    user: User;
}

const DEFAULT_EXECUTIVE_DEADLINE = '2026-06-30T23:59:59Z';
const DOC_TYPE_ORDER: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];

type ViewScale = 'YEARS' | 'MONTHS';
type StatusFilter = 'DONE' | 'ON_TRACK' | 'RISK' | 'OVERDUE' | 'PENDING' | 'ALL';

const AdminGantt: React.FC<Props> = ({ user }) => {
    const [documents, setDocuments] = useState<Document[]>([]);
    const [allUsers, setAllUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [updatingId, setUpdatingId] = useState<string | null>(null);

    // Estado de Expansión
    const [expandedProjects, setExpandedProjects] = useState<Record<string, boolean>>({});
    const [expandedMicros, setExpandedMicros] = useState<Record<string, boolean>>({});

    // Filtros
    const [filterProject, setFilterProject] = useState('');
    const [filterMacro, setFilterMacro] = useState('');
    const [filterProcess, setFilterProcess] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState('');
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState<StatusFilter>('ALL');

    // Estado de Vista
    const [viewScale, setViewScale] = useState<ViewScale>('MONTHS');
    const currentYear = new Date().getFullYear();

    // Modal
    const [editModalDoc, setEditModalDoc] = useState<Document | null>(null);
    const [newDeadline, setNewDeadline] = useState('');

    const canEditDates = user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR;
    const isAnalyst = user.role === UserRole.ANALYST;

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [docs, fullHierarchy, usersList] = await Promise.all([
                DocumentService.getAll(),
                HierarchyService.getFullHierarchy(),
                UserService.getAll()
            ]);

            setAllUsers(usersList);

            const realDocMap = new Map<string, Document>();
            docs.forEach(doc => {
                if (doc.project && (doc.microprocess || doc.title)) {
                    const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                    const docType = doc.docType || 'AS IS';
                    const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                    const existing = realDocMap.get(key);
                    if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                        realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                    }
                }
            });

            const unifiedList: Document[] = [];
            const initialProjects: Record<string, boolean> = {};

            Object.keys(fullHierarchy).forEach(proj => {
                initialProjects[proj] = true; // Por defecto expandidos
                Object.keys(fullHierarchy[proj]).forEach(macro => {
                    Object.keys(fullHierarchy[proj][macro]).forEach(proc => {
                        fullHierarchy[proj][macro][proc].forEach(node => {
                            if (node.active === false) return;
                            if (isAnalyst && !node.assignees?.includes(user.id)) return;

                            const requiredTypes = node.requiredTypes?.length > 0 
                                ? node.requiredTypes 
                                : ['AS IS', 'FCE', 'PM', 'TO BE'];

                            DOC_TYPE_ORDER.forEach(type => {
                                if (!requiredTypes.includes(type)) return;
                                const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;

                                if (realDocMap.has(key)) {
                                    unifiedList.push({ 
                                        ...realDocMap.get(key)!, 
                                        project: proj, 
                                        macroprocess: macro,
                                        process: proc,
                                        microprocess: node.name, 
                                        assignees: node.assignees 
                                    });
                                } else {
                                    unifiedList.push({
                                        id: `virtual-${key}`,
                                        title: `${node.name} - ${type}`,
                                        description: 'Pendiente de inicio',
                                        project: proj,
                                        macroprocess: macro,
                                        process: proc,
                                        microprocess: node.name,
                                        docType: type,
                                        state: DocState.NOT_STARTED,
                                        version: '-',
                                        progress: 0,
                                        files: [],
                                        createdAt: new Date().toISOString(),
                                        updatedAt: new Date(0).toISOString(),
                                        assignees: node.assignees || [],
                                        authorId: '',
                                        authorName: 'Sistema'
                                    } as Document);
                                }
                            });
                        });
                    });
                });
            });

            setDocuments(unifiedList);
            setExpandedProjects(initialProjects);
        } catch (e) {
            console.error("Error loading Gantt data", e);
        } finally {
            setLoading(false);
        }
    };

    const getStatusInfo = (doc: Document) => {
        const now = new Date();
        const deadline = doc.expectedEndDate ? new Date(doc.expectedEndDate) : new Date(DEFAULT_EXECUTIVE_DEADLINE);

        if (doc.state === DocState.APPROVED) return { status: 'DONE' as const, color: 'bg-emerald-500', label: 'Terminado' };
        if (doc.state === DocState.NOT_STARTED) return { status: 'PENDING' as const, color: 'bg-slate-300', label: 'No Iniciado' };

        if (now > deadline) return { status: 'OVERDUE' as const, color: 'bg-rose-500', label: 'Atrasado' };

        const created = new Date(doc.createdAt);
        const totalDuration = deadline.getTime() - created.getTime();
        const elapsed = now.getTime() - created.getTime();
        const ratio = elapsed / totalDuration;

        if (ratio > 0.8 && doc.progress < 80) return { status: 'RISK' as const, color: 'bg-amber-500', label: 'En Riesgo' };
        return { status: 'ON_TRACK' as const, color: 'bg-indigo-500', label: 'En Plazo' };
    };

    const filteredDocuments = useMemo(() => {
        return documents.filter(d => {
            if (filterProject && d.project !== filterProject) return false;
            if (filterMacro && d.macroprocess !== filterMacro) return false;
            if (filterProcess && d.process !== filterProcess) return false;
            if (filterAnalyst && !d.assignees?.includes(filterAnalyst)) return false;
            if (statusFilter !== 'ALL' && getStatusInfo(d).status !== statusFilter) return false;
            if (searchTerm) {
                const term = searchTerm.toLowerCase();
                return d.microprocess?.toLowerCase().includes(term) || d.title.toLowerCase().includes(term);
            }
            return true;
        });
    }, [documents, filterProject, filterMacro, filterProcess, filterAnalyst, statusFilter, searchTerm]);

    const groupedData = useMemo(() => {
        const groups: Record<string, Record<string, Document[]>> = {};
        filteredDocuments.forEach(doc => {
            const p = doc.project || 'Sin Proyecto';
            const m = doc.microprocess || 'General';
            if (!groups[p]) groups[p] = {};
            if (!groups[p][m]) groups[p][m] = [];
            groups[p][m].push(doc);
        });
        return groups;
    }, [filteredDocuments]);

    const availableMacros = useMemo(() => Array.from(new Set(documents.filter(d => !filterProject || d.project === filterProject).map(d => d.macroprocess).filter(Boolean))).sort(), [documents, filterProject]);
    const availableProcesses = useMemo(() => Array.from(new Set(documents.filter(d => (!filterProject || d.project === filterProject) && (!filterMacro || d.macroprocess === filterMacro)).map(d => d.process).filter(Boolean))).sort(), [documents, filterProject, filterMacro]);

    // Timeline Configuration
    const timelineHeaders = useMemo(() => {
        if (viewScale === 'MONTHS') return ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
        return ['2023', '2024', '2025', '2026'];
    }, [viewScale]);

    const getPositionInGantt = (dateStr: string) => {
        const date = new Date(dateStr).getTime();
        if (viewScale === 'MONTHS') {
            const startOfYear = new Date(currentYear, 0, 1).getTime();
            const endOfYear = new Date(currentYear, 11, 31, 23, 59, 59).getTime();
            if (date <= startOfYear) return 0;
            if (date >= endOfYear) return 100;
            return ((date - startOfYear) / (endOfYear - startOfYear)) * 100;
        } else {
            // Rango ampliado a 2026 para cubrir la meta institucional
            const startRange = new Date(2023, 0, 1).getTime();
            const endRange = new Date(2026, 11, 31, 23, 59, 59).getTime();
            if (date <= startRange) return 0;
            if (date >= endRange) return 100;
            return ((date - startRange) / (endRange - startRange)) * 100;
        }
    };

    const handleUpdateDeadline = async () => {
        if (!canEditDates || !editModalDoc || !newDeadline) return;
        setUpdatingId(editModalDoc.id);
        try {
            await DocumentService.updateDeadline(editModalDoc.id, new Date(newDeadline).toISOString());
            setEditModalDoc(null);
            await loadData();
        } catch (e) {
            alert("Error al actualizar la fecha");
        } finally {
            setUpdatingId(null);
        }
    };

    const handleExportExcel = () => {
        if (filteredDocuments.length === 0) return;
        const headers = ['PROYECTO', 'MACROPROCESO', 'PROCESO', 'MICROPROCESO', 'TIPO', 'VERSION', 'ESTADO ACTUAL', 'ESTADO OPERATIVO', 'INICIO', 'META', 'SITUACION'];
        const rows = filteredDocuments.map(doc => {
            const status = getStatusInfo(doc);
            const deadline = doc.expectedEndDate ? new Date(doc.expectedEndDate) : new Date(DEFAULT_EXECUTIVE_DEADLINE);
            return [
                doc.project, doc.macroprocess, doc.process, doc.microprocess, doc.docType, doc.version, `${STATE_CONFIG[doc.state].label.split('(')[0].trim()} (${doc.progress}%)`, 
                STATE_CONFIG[doc.state].label.split('(')[0], 
                new Date(doc.createdAt).toLocaleDateString(), deadline.toLocaleDateString(), status.label
            ];
        });
        const csvContent = [headers.join(';'), ...rows.map(r => r.map(cell => `"${cell}"`).join(';'))].join('\n');
        const blob = new Blob(["\ufeff", csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.setAttribute('href', url); link.setAttribute('download', `SGD_Gantt_Estrategico_${new Date().toISOString().split('T')[0]}.csv`);
        link.style.visibility = 'hidden'; document.body.appendChild(link); link.click(); document.body.removeChild(link);
    };

    const toggleProject = (proj: string) => {
        setExpandedProjects(prev => ({ ...prev, [proj]: !prev[proj] }));
    };

    const toggleMicro = (proj: string, micro: string) => {
        const key = `${proj}-${micro}`;
        setExpandedMicros(prev => ({ ...prev, [key]: !prev[key] }));
    };

    const expandAll = () => {
        const allP: Record<string, boolean> = {};
        const allM: Record<string, boolean> = {};
        Object.keys(groupedData).forEach(p => {
            allP[p] = true;
            Object.keys(groupedData[p]).forEach(m => {
                allM[`${p}-${m}`] = true;
            });
        });
        setExpandedProjects(allP);
        setExpandedMicros(allM);
    };

    const collapseAll = () => {
        setExpandedProjects({});
        setExpandedMicros({});
    };

    const toggleStatusFilter = (status: StatusFilter) => {
        setStatusFilter(prev => prev === status ? 'ALL' : status);
    };

    const todayPos = useMemo(() => getPositionInGantt(new Date().toISOString()), [viewScale]);

    return (
        <div className="space-y-6 pb-20 max-w-[1600px] mx-auto animate-fadeIn">
            {/* CABECERA */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-black text-slate-900 flex items-center gap-3">
                        <div className="p-2 bg-slate-900 rounded-xl text-white shadow-lg">
                            <CalendarRange size={24} />
                        </div>
                        Diagrama Gantt
                    </h1>
                    <p className="text-slate-500 text-sm mt-1 font-medium italic">Cronograma Táctico Institucional y Control de Plazos.</p>
                </div>
                <div className="flex flex-wrap gap-2">
                    <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm mr-2">
                        <button onClick={expandAll} className="p-2 hover:bg-slate-50 text-slate-600 rounded-lg" title="Expandir Todo"><Maximize2 size={16} /></button>
                        <button onClick={collapseAll} className="p-2 hover:bg-slate-50 text-slate-600 rounded-lg" title="Contraer Todo"><Minimize2 size={16} /></button>
                    </div>
                    <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm mr-2">
                        <button onClick={() => setViewScale('YEARS')} className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase transition-all ${viewScale === 'YEARS' ? 'bg-slate-900 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>Años</button>
                        <button onClick={() => setViewScale('MONTHS')} className={`px-4 py-1.5 rounded-lg text-[10px] font-black uppercase transition-all ${viewScale === 'MONTHS' ? 'bg-slate-900 text-white shadow-md' : 'text-slate-400 hover:text-slate-600'}`}>Meses</button>
                    </div>
                    <button onClick={handleExportExcel} className="flex items-center gap-2 px-6 py-2.5 bg-emerald-600 hover:bg-emerald-700 text-white rounded-xl font-black text-[10px] uppercase tracking-widest shadow-lg transition-all active:scale-95">
                        <FileSpreadsheet size={18} /> Exportar
                    </button>
                </div>
            </div>

            {/* FILTROS Y DRILL DOWN */}
            <div className="space-y-4">
                <div className="bg-white p-5 rounded-3xl shadow-sm border border-slate-200 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-4 items-end">
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Proyecto</label>
                        <select value={filterProject} onChange={(e) => { setFilterProject(e.target.value); setFilterMacro(''); setFilterProcess(''); }} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-2.5 text-xs font-bold outline-none focus:ring-2 focus:ring-indigo-500/20">
                            <option value="">TODOS</option>
                            <option value="HPC">HPC</option>
                            <option value="HSR">HSR</option>
                        </select>
                    </div>
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Macroproceso</label>
                        <select value={filterMacro} onChange={(e) => { setFilterMacro(e.target.value); setFilterProcess(''); }} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-2.5 text-xs font-bold outline-none focus:ring-2 focus:ring-indigo-500/20">
                            <option value="">TODOS</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                    </div>
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Proceso</label>
                        <select value={filterProcess} onChange={(e) => setFilterProcess(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-2.5 text-xs font-bold outline-none focus:ring-2 focus:ring-indigo-500/20">
                            <option value="">TODOS</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>
                    {!isAnalyst && (
                        <div className="space-y-1.5">
                            <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Analista</label>
                            <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-xl p-2.5 text-xs font-bold outline-none focus:ring-2 focus:ring-indigo-500/20">
                                <option value="">TODOS</option>
                                {allUsers.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                            </select>
                        </div>
                    )}
                    <div className="space-y-1.5">
                        <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Buscar Microproceso</label>
                        <div className="relative">
                            <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                            <input type="text" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} placeholder="Ej: Admisión..." className="w-full pl-9 pr-4 py-2.5 bg-slate-50 border border-slate-200 rounded-xl text-xs font-bold outline-none focus:ring-2 focus:ring-indigo-500/20" />
                        </div>
                    </div>
                </div>

                {/* LEYENDA INTERACTIVA (DRILL DOWN) */}
                <div className="flex flex-wrap items-center gap-3 px-2">
                    <div className="flex items-center gap-2 text-[10px] font-black text-slate-400 uppercase tracking-widest mr-4">
                        <Filter size={14} className="text-slate-300" />
                        Drill Down:
                    </div>
                    <FilterableLegend 
                        color="bg-rose-500" 
                        label="Atrasado" 
                        active={statusFilter === 'OVERDUE'} 
                        onClick={() => toggleStatusFilter('OVERDUE')} 
                    />
                    <FilterableLegend 
                        color="bg-amber-500" 
                        label="En Riesgo" 
                        active={statusFilter === 'RISK'} 
                        onClick={() => toggleStatusFilter('RISK')} 
                    />
                    <FilterableLegend 
                        color="bg-indigo-500" 
                        label="En Plazo" 
                        active={statusFilter === 'ON_TRACK'} 
                        onClick={() => toggleStatusFilter('ON_TRACK')} 
                    />
                    <FilterableLegend 
                        color="bg-emerald-500" 
                        label="Terminado" 
                        active={statusFilter === 'DONE'} 
                        onClick={() => toggleStatusFilter('DONE')} 
                    />
                    <FilterableLegend 
                        color="bg-slate-300" 
                        label="No Iniciado" 
                        active={statusFilter === 'PENDING'} 
                        onClick={() => toggleStatusFilter('PENDING')} 
                    />
                    {statusFilter !== 'ALL' && (
                        <button 
                            onClick={() => setStatusFilter('ALL')}
                            className="text-[10px] font-black text-indigo-600 hover:text-indigo-800 uppercase tracking-tighter ml-4 flex items-center gap-1 bg-indigo-50 px-3 py-1.5 rounded-full border border-indigo-100"
                        >
                            <X size={12} /> Limpiar Filtro de Estado
                        </button>
                    )}
                </div>
            </div>

            {/* TABLA GANTT JERÁRQUICA */}
            <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/40 border border-slate-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse min-w-[1300px]">
                        <thead className="bg-slate-900 text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] border-b border-slate-800">
                            <tr>
                                <th className="px-6 py-5 w-64">Jerarquía Organizacional</th>
                                <th className="px-6 py-5 w-48">Tipo / Estado</th>
                                <th className="px-6 py-5 w-24 text-center">Versión</th>
                                <th className="px-6 py-5 w-40 text-center">Progreso</th>
                                <th className="px-6 py-5">
                                    <div className="flex items-center justify-between mb-2">
                                        <span>Cronograma Táctico</span>
                                    </div>
                                    <div className="grid grid-cols-12 gap-0 border-t border-slate-800/50 mt-2">
                                        {timelineHeaders.map((h, i) => (
                                            <div key={i} className={`text-center py-2 border-r border-slate-800/20 last:border-0 ${viewScale === 'MONTHS' ? 'col-span-1' : 'col-span-3'}`}>
                                                {h}
                                            </div>
                                        ))}
                                    </div>
                                </th>
                                <th className="px-6 py-5 w-16 text-right"></th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-100">
                            {Object.keys(groupedData).length === 0 ? (
                                <tr><td colSpan={6} className="py-24 text-center opacity-30 italic">No se encontraron registros {statusFilter !== 'ALL' ? `con estado "${statusFilter}"` : ''}.</td></tr>
                            ) : Object.keys(groupedData).map(project => {
                                const isProjectExpanded = expandedProjects[project];
                                const projectDocs = Object.values(groupedData[project]).flat() as Document[];
                                const projectAverageProgress = projectDocs.length > 0 
                                    ? Math.round(projectDocs.reduce((acc: number, d: Document) => acc + d.progress, 0) / projectDocs.length)
                                    : 0;

                                return (
                                    <React.Fragment key={project}>
                                        {/* HEADER DE PROYECTO */}
                                        <tr onClick={() => toggleProject(project)} className="bg-slate-50 cursor-pointer hover:bg-slate-100 transition-colors group">
                                            <td className="px-6 py-4 font-black text-slate-800 flex items-center gap-2">
                                                {isProjectExpanded ? <ChevronDown size={18} className="text-indigo-600" /> : <ChevronRight size={18} className="text-slate-400" />}
                                                <span className="bg-slate-900 text-white px-2 py-0.5 rounded text-[10px] tracking-widest">{project}</span>
                                                <span className="text-xs ml-2 text-slate-500 font-medium">({Object.keys(groupedData[project]).length} microprocesos)</span>
                                            </td>
                                            <td className="px-6 py-4"></td>
                                            <td className="px-6 py-4"></td>
                                            <td className="px-6 py-4 text-center">
                                                <div className="text-[10px] font-black text-indigo-600">{projectAverageProgress}% AVG</div>
                                            </td>
                                            <td className="px-6 py-4">
                                                {!isProjectExpanded && (
                                                    <div className="h-1.5 w-full bg-slate-200 rounded-full overflow-hidden">
                                                        <div className="h-full bg-indigo-500 transition-all duration-700" style={{ width: `${projectAverageProgress}%` }}></div>
                                                    </div>
                                                )}
                                            </td>
                                            <td className="px-6 py-4"></td>
                                        </tr>

                                        {isProjectExpanded && Object.keys(groupedData[project]).map((micro) => {
                                            const microKey = `${project}-${micro}`;
                                            const isMicroExpanded = expandedMicros[microKey];
                                            const microDocs = groupedData[project][micro];
                                            const microAverageProgress = Math.round(microDocs.reduce((acc, d) => acc + d.progress, 0) / microDocs.length);

                                            return (
                                                <React.Fragment key={microKey}>
                                                    {/* HEADER DE MICROPROCESO */}
                                                    <tr onClick={() => toggleMicro(project, micro)} className="bg-white cursor-pointer hover:bg-slate-50/80 transition-colors border-l-4 border-indigo-500">
                                                        <td className="px-10 py-3 font-bold text-slate-700 flex items-center gap-2">
                                                            {isMicroExpanded ? <ChevronDown size={14} className="text-indigo-500" /> : <ChevronRight size={14} className="text-slate-300" />}
                                                            <span className="text-xs uppercase tracking-tight truncate max-w-[300px]">{micro}</span>
                                                        </td>
                                                        <td className="px-6 py-3">
                                                            {!isMicroExpanded && (
                                                                <div className="flex gap-1">
                                                                    {microDocs.map(d => (
                                                                        <div key={d.id} className={`w-2 h-2 rounded-full ${getStatusInfo(d).color}`} title={d.docType}></div>
                                                                    ))}
                                                                </div>
                                                            )}
                                                        </td>
                                                        <td className="px-6 py-3"></td>
                                                        <td className="px-6 py-3 text-center">
                                                            <span className="text-[10px] font-bold text-slate-500">{microAverageProgress}%</span>
                                                        </td>
                                                        <td className="px-6 py-3">
                                                            {!isMicroExpanded && (
                                                                <div className="h-1 w-full bg-slate-100 rounded-full overflow-hidden">
                                                                    <div className="h-full bg-indigo-400" style={{ width: `${microAverageProgress}%` }}></div>
                                                                </div>
                                                            )}
                                                        </td>
                                                        <td className="px-6 py-3"></td>
                                                    </tr>

                                                    {/* FILAS DE DOCUMENTOS INDIVIDUALES */}
                                                    {isMicroExpanded && microDocs.map((doc) => {
                                                        const statusInfo = getStatusInfo(doc);
                                                        const isApproved = doc.state === DocState.APPROVED;
                                                        const barStart = doc.createdAt;
                                                        const barEnd = isApproved ? doc.updatedAt : (doc.expectedEndDate || DEFAULT_EXECUTIVE_DEADLINE);
                                                        const startPos = getPositionInGantt(barStart);
                                                        const endPos = getPositionInGantt(barEnd);
                                                        const duration = Math.max(1.5, endPos - startPos);

                                                        return (
                                                            <tr key={doc.id} className="hover:bg-indigo-50/30 transition-all group bg-slate-50/20">
                                                                <td className="px-16 py-3">
                                                                    <div className="flex items-center gap-2">
                                                                        <div className="w-1.5 h-1.5 rounded-full bg-indigo-200"></div>
                                                                        <span className="text-[10px] font-black text-slate-500 uppercase">{doc.docType}</span>
                                                                    </div>
                                                                </td>
                                                                <td className="px-6 py-3">
                                                                    <div className={`inline-block px-2 py-0.5 rounded-full text-[8px] font-black border ${doc.state === DocState.NOT_STARTED ? 'bg-white text-slate-300 border-slate-100' : STATE_CONFIG[doc.state].color}`}>
                                                                        {STATE_CONFIG[doc.state].label.split('(')[0].trim()}
                                                                    </div>
                                                                </td>
                                                                <td className="px-6 py-3 text-center">
                                                                    <span className="text-[10px] font-mono font-black text-slate-600 bg-slate-100 px-1.5 py-0.5 rounded">
                                                                        {formatVersionForDisplay(doc.version)}
                                                                    </span>
                                                                </td>
                                                                <td className="px-6 py-3 text-center">
                                                                    <span className="text-[9px] font-mono text-slate-400 font-bold">{doc.progress}%</span>
                                                                </td>
                                                                <td className="px-6 py-3">
                                                                    <div className="relative h-8 flex items-center">
                                                                        {/* Grid Background */}
                                                                        <div className="absolute inset-0 grid grid-cols-12 pointer-events-none opacity-[0.03]">
                                                                            {timelineHeaders.map((_, i) => <div key={i} className={`border-r border-slate-900 last:border-0 ${viewScale === 'MONTHS' ? 'col-span-1' : 'col-span-3'}`}></div>)}
                                                                        </div>

                                                                        {/* Indicador de HOY */}
                                                                        {viewScale === 'MONTHS' && todayPos > 0 && todayPos < 100 && (
                                                                            <div className="absolute top-0 bottom-0 w-px bg-rose-500/20 z-10" style={{ left: `${todayPos}%` }}></div>
                                                                        )}

                                                                        {/* Main Bar */}
                                                                        <div 
                                                                            className="absolute h-4 rounded-full bg-slate-100 border border-slate-200 overflow-hidden shadow-sm transition-all group-hover:scale-[1.01] cursor-help"
                                                                            style={{ left: `${startPos}%`, width: `${duration}%` }}
                                                                            title={`Plazo: ${new Date(barStart).toLocaleDateString()} al ${new Date(barEnd).toLocaleDateString()}`}
                                                                        >
                                                                            <div 
                                                                                className={`h-full ${statusInfo.color} transition-all duration-1000 ease-out`}
                                                                                style={{ width: `${isApproved ? 100 : doc.progress}%` }}
                                                                            ></div>
                                                                        </div>
                                                                    </div>
                                                                </td>
                                                                <td className="px-6 py-3 text-right">
                                                                    {(canEditDates && !isAnalyst && !doc.id.startsWith('virtual-') && !isApproved) && (
                                                                        <button onClick={() => { setEditModalDoc(doc); setNewDeadline(doc.expectedEndDate ? doc.expectedEndDate.split('T')[0] : DEFAULT_EXECUTIVE_DEADLINE.split('T')[0]); }} className="p-1 text-slate-300 hover:text-indigo-600 transition-colors">
                                                                            <Calendar size={12} />
                                                                        </button>
                                                                    )}
                                                                </td>
                                                            </tr>
                                                        );
                                                    })}
                                                </React.Fragment>
                                            );
                                        })}
                                    </React.Fragment>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>

            {/* MODAL AJUSTE DE FECHA */}
            {canEditDates && !isAnalyst && editModalDoc && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-md animate-fadeIn">
                    <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md overflow-hidden border border-white/20">
                        <div className="p-8 border-b border-slate-100">
                            <div className="flex justify-between items-center mb-6">
                                <div className="p-3 bg-indigo-50 rounded-2xl text-indigo-600">
                                    <Clock size={24} />
                                </div>
                                <button onClick={() => setEditModalDoc(null)} className="text-slate-400 hover:text-slate-900 transition-colors">
                                    <X size={28} />
                                </button>
                            </div>
                            <h3 className="text-xl font-black text-slate-900">Ajustar Fecha Meta</h3>
                            <p className="text-slate-500 text-xs font-medium uppercase tracking-widest mt-1">Estrategia Institucional</p>
                        </div>
                        <div className="p-8 space-y-6">
                            <div className="bg-slate-900 p-4 rounded-2xl text-white">
                                <span className="text-[8px] font-black uppercase text-indigo-400 block mb-1">Entregable</span>
                                <span className="text-xs font-black uppercase">{editModalDoc.title}</span>
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-black text-slate-400 uppercase ml-2">Nueva Fecha Compromiso</label>
                                <input type="date" value={newDeadline} onChange={(e) => setNewDeadline(e.target.value)} min={editModalDoc.createdAt.split('T')[0]} className="w-full p-4 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-indigo-500/10 outline-none font-black text-sm" />
                            </div>
                            <div className="flex gap-3 pt-2">
                                <button onClick={() => setEditModalDoc(null)} className="flex-1 py-4 text-xs font-black uppercase text-slate-400 hover:text-slate-600 transition-colors">Cerrar</button>
                                <button onClick={handleUpdateDeadline} disabled={!newDeadline || updatingId === editModalDoc.id} className="flex-[2] bg-indigo-600 hover:bg-indigo-700 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-100 disabled:opacity-50 flex items-center justify-center gap-2">
                                    {updatingId === editModalDoc.id ? <Loader2 size={16} className="animate-spin" /> : <Save size={16} />} Actualizar
                                </button>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const FilterableLegend = ({ color, label, active, onClick }: { color: string, label: string, active: boolean, onClick: () => void }) => (
    <button 
        onClick={onClick}
        className={`flex items-center gap-2.5 px-4 py-2 rounded-full border transition-all active:scale-95 ${active ? 'bg-white border-indigo-200 shadow-md ring-2 ring-indigo-500/10 scale-105' : 'border-transparent hover:bg-white/60'}`}
    >
        <div className={`w-3 h-3 rounded-full ${color} shadow-sm ${active ? 'animate-pulse' : ''}`}></div>
        <span className={`text-[10px] font-black uppercase tracking-widest transition-colors ${active ? 'text-indigo-600' : 'text-slate-500'}`}>{label}</span>
    </button>
);

export default AdminGantt;
